def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        cap = bins[i]
        if cap == 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 1:
            priorities[i] = np.inf
        else:
            penalty = 0
            for j in range(1, 5):
                penalty += np.sin(j * ratio * np.pi)
            if ratio < 0.5:
                priorities[i] = (1 - ratio) * 10 - penalty
            elif 0.5 <= ratio < 1:
                priorities[i] = (1 - ratio) * 5 - penalty / 2
            else:
                priorities[i] = np.inf
            if cap % 2 == 0:
                priorities[i] *= 1.1
            else:
                priorities[i] *= 0.9
    return priorities
